import { Lesson } from './types';
import { createLesson } from './data_helpers';

export const redLessonsB1: Lesson[] = [
  createLesson('g3-red-b1-l1', 'L1: 3ª Série — Revisão Diagnóstica das Competências ENEM', 'redacao', 'Bem-vindos ao ano decisivo. A redação do ENEM vale 200 pontos por competência (total 1000) e é a peça mais pontuada do exame. Vamos fazer um diagnóstico completo: Competência 1 (norma culta), Competência 2 (compreensão do tema e tipo textual), Competência 3 (seleção e organização dos argumentos), Competência 4 (mecanismos linguísticos de coesão), Competência 5 (proposta de intervenção social). Produziremos uma redação diagnóstica para identificar onde cada aluno precisa avançar.', ['Qual das 5 competências do ENEM você considera sua maior fraqueza? Justifique.', 'Escreva uma redação diagnóstica sobre o tema: "Os desafios da educação pública no Brasil contemporâneo".']),
  createLesson('g3-red-b1-l2', 'L2: Leitura Crítica dos Textos Motivadores', 'redacao', 'Os textos motivadores do ENEM funcionam como pistas, não como respostas. Erros comuns: copiar frases dos textos (fuga ao tema), resumir os textos sem posicionar-se (apenas relato), ignorar textos não verbais (gráficos, charges, fotos). Estratégia correta: leia todos os textos, identifique o fio condutor temático, extraia dados/ideias que possam ser repertório, e construa seu próprio argumento. Textos motivadores são trampolins, não muletas. Praticaremos com coletâneas de ENEMs anteriores.', ['Por que copiar frases dos textos motivadores prejudica a nota na Competência 2?', 'Analise uma coletânea de textos e identifique o fio condutor temático central.']),
  createLesson('g3-red-b1-l3', 'L3: Tese de Alto Impacto — Competência 2 Nível 200', 'redacao', 'A tese é a resposta argumentativa ao tema. Para nota 200 na C2, ela deve: (1) recortar o tema com precisão (não ser vaga), (2) apresentar um ponto de vista claro e defensável, (3) antecipar os eixos de desenvolvimento dos parágrafos, (4) ser original sem ser absurda. Modelos de tese nível 200: "A violência contra a mulher no Brasil é perpetuada pela cultura do silêncio, pelo despreparo institucional e pela ausência de políticas de masculinidade positiva." Compare com teses fracas e entenda por que falham. A tese é o coração da redação.', ['Qual a diferença entre uma tese "genérica" e uma tese "recortada"? Exemplifique.', 'Reescreva esta tese fraca tornando-a nível 200: "A educação é muito importante para o Brasil."']),
  createLesson('g3-red-b1-l4', 'L4: Introdução — A Arte de Contextualizar', 'redacao', 'A introdução tem dois movimentos: contextualização e tese. A contextualização deve ser relevante ao tema (não qualquer frase histórica genérica) e criar uma ponte lógica até a tese. Estratégias de contextualização: (1) Repertório histórico — eventos que originaram o problema; (2) Citação de pensador — filósofo, sociólogo ou cientista pertinente; (3) Dado estatístico — cifra que dimensiona o problema; (4) Situação hipotética — narrativa em 3ª pessoa que representa o problema; (5) Conceito filosófico — definição que ilumina o tema. Cada estratégia tem vantagens e riscos. Dominar pelo menos 3 é essencial para a prova.', ['Quais são as 5 estratégias de contextualização estudadas? Apresente exemplos de cada uma.', 'Escreva uma introdução completa usando a estratégia de citação de pensador para o tema "Saúde mental dos jovens no Brasil".']),
  createLesson('g3-red-b1-l5', 'L5: Desenvolvimento — Parágrafo de Alta Qualidade', 'redacao', 'O parágrafo de desenvolvimento de nível 200 tem 3 camadas: (1) Tópico frasal — afirmação que sustenta a tese; (2) Desenvolvimento — explicação, análise causal, dados, referência cultural; (3) Conclusão parcial — síntese que conecta ao tema central. O erro mais comum é fazer parágrafo de 2 camadas (tópico + exemplo) sem análise. O ENEM recompensa raciocínio, não listas de exemplos. Quantidade ideal: 2 parágrafos de desenvolvimento com 7-10 linhas cada. Veja exemplos de parágrafos nota 0 vs. nota 200 e analise as diferenças.', ['Quais são as 3 camadas de um parágrafo de desenvolvimento de alto nível?', 'Escreva um parágrafo de desenvolvimento sobre "desigualdade de acesso à tecnologia" usando as 3 camadas.']),
  createLesson('g3-red-b1-l6', 'L6: Conclusão — Proposta de Intervenção Perfeita (C5)', 'redacao', 'A Competência 5 exige uma proposta de intervenção social que respeite os direitos humanos e tenha 5 elementos: (1) Agente — quem vai agir (Estado, escola, mídia, empresas, ONGs); (2) Ação — o que será feito (verbo de ação preciso); (3) Meio/Modo — como será feito (mecanismo concreto); (4) Finalidade — para que (conectada à tese); (5) Detalhamento — especificidade que mostra profundidade. Proposta nota 200: "O Ministério da Educação deve implementar, por meio de parceria com universidades federais, programas de formação continuada para professores em saúde mental, a fim de capacitá-los a identificar e encaminhar alunos em sofrimento psíquico, promovendo um ambiente escolar acolhedor." Veja a diferença de proposta nota 80 e note cada elemento.', ['Quais são os 5 elementos da proposta de intervenção nota 200?', 'Escreva uma proposta de intervenção completa para o tema "Violência nas escolas brasileiras".']),
  createLesson('g3-red-b1-l7', 'L7: Coesão Avançada — Competência 4 Nível 200', 'redacao', 'Para nota 200 na C4, você precisa dominar 3 tipos de coesão: (1) Referencial — pronomes, elipses, substituições lexicais que evitam repetição; (2) Sequencial — conectivos que organizam o raciocínio (causa, consequência, concessão, adição, oposição); (3) Lexical — uso de sinônimos, hiperônimos, expressões equivalentes que criam variedade e coerência. Erros que derrubam nota: excesso de "portanto", começar parágrafo com "Diante disso", lista de conectivos sem raciocínio. A coesão deve ser invisível — o leitor deve sentir fluidez, não ver "costura". Texto coeso parece conversa inteligente, não texto de vestibular.', ['Qual a diferença entre coesão referencial, sequencial e lexical? Exemplifique cada uma.', 'Reescreva o trecho abaixo melhorando a coesão: "O problema é grave. O problema afeta muitas pessoas. O problema precisa ser resolvido."']),
  createLesson('g3-red-b1-l8', 'L8: Norma Culta no ENEM — Competência 1 sem Erros', 'redacao', 'A Competência 1 avalia o domínio da norma culta escrita. Pontos críticos para o ENEM: (1) Concordância verbal e nominal (os casos difíceis: sujeito composto, verbos impessoais, pronomes indefinidos); (2) Regência verbal e nominal (verbos que mais caem: aspirar, visar, assistir, obedecer, preferir); (3) Crase (quando não usar: antes de verbos, masculinos, pronomes pessoais); (4) Pontuação (vírgula entre sujeito e verbo, uso de ponto-e-vírgula); (5) Uso correto de pronomes (colocação, formas oblíquas). Estratégia: tenha uma "lista de proibições" pessoal — as construções que você erra frequentemente. Evite o que não domina. Zona de conforto gramatical.', ['Corrija os erros de norma culta: "Haveram muitos alunos que chegaram atrasado na escola, mas a diretora, junto com os professores, ainda esperou eles."', 'Quais são os 5 aspectos gramaticais mais cobrados pelo ENEM na Competência 1?']),
  createLesson('g3-red-b1-l9', 'L9: Repertório Cultural — Construindo sua Biblioteca Mental', 'redacao', 'Repertório cultural é o conjunto de referências (filosóficas, históricas, literárias, científicas, culturais) que você usa para contextualizar e argumentar. Para o ENEM 2026, construa um repertório em 6 áreas: (1) Filosofia — pelo menos 8 pensadores (Platão, Aristóteles, Descartes, Rousseau, Kant, Marx, Nietzsche, Foucault, Arendt, Bourdieu); (2) Sociologia — Durkheim, Weber, Giddens, Bauman; (3) História do Brasil — ditadura, abolição, redemocratização; (4) Literatura — Machado de Assis, Graciliano Ramos, Carolina de Jesus, Conceição Evaristo; (5) Ciência e tecnologia — Darwin, big data, algoritmos; (6) Arte e cultura — cinema, música brasileira, arte de protesto. O repertório deve ser preciso, não inventado.', ['Por que um repertório cultural vago ou impreciso pode prejudicar a nota em vez de ajudar?', 'Monte uma "ficha de repertório" para o tema educação, listando pelo menos 5 referências de áreas diferentes.']),
  createLesson('g3-red-b1-l10', 'L10: Tema — Violência e Segurança Pública', 'redacao', 'Violência é tema recorrente no ENEM. Ângulos possíveis: violência estrutural (Bourdieu), encarceramento em massa, violência doméstica, racismo como violência, juventude negra periférica. Dados: Brasil tem ~45.000 homicídios/ano (Atlas da Violência); 74% das vítimas são negros (IPEA). Repertório filosófico: Hannah Arendt distingue violência (instrumental, destrutiva) de poder (legítimo). Walter Benjamin: violência fundadora e mantenedora do direito. Propostas cabíveis: investimento em medidas socioeducativas, reforma prisional, programas de mediação de conflitos, educação para paz, desarmamento. Evite redações punitivistas sem análise das causas estruturais.', ['Como Bourdieu explica a "violência simbólica" e como esse conceito pode ser usado em redação sobre segurança pública?', 'Escreva uma redação completa sobre: "Os impactos da violência urbana na qualidade de vida da população brasileira".']),
  createLesson('g3-red-b1-l11', 'L11: Tema — Tecnologia, Privacidade e Sociedade', 'redacao', 'Tecnologia e privacidade: um dos grandes temas contemporâneos. Dados: Brasil tem 165 milhões de usuários de internet; escândalo Cambridge Analytica (2018) revelou uso de dados para manipulação política; Lei Geral de Proteção de Dados (LGPD, 2020) é resposta legislativa. Repertório: Zygmunt Bauman e "vigilância líquida"; Michel Foucault e o panoptismo aplicado à era digital; Shoshana Zuboff e "capitalismo de vigilância". Ângulos: fake news e democracia, vício em redes sociais, exclusão digital, inteligência artificial e empregos, algoritmos e discriminação racial. Proposta: regulação de plataformas, educação midiática, fortalecimento da LGPD, transparência algorítmica.', ['Como o conceito de "panoptismo" de Foucault se aplica à vigilância digital contemporânea?', 'Escreva uma redação sobre: "Os riscos da desinformação para a democracia brasileira".']),
  createLesson('g3-red-b1-l12', 'L12: Tema — Meio Ambiente e Sustentabilidade', 'redacao', 'Meio ambiente é tema praticamente garantido no ENEM. Perspectivas: crise climática (IPCC: aquecimento de 1,5°C até 2030-2050), desmatamento da Amazônia (70% da biodiversidade sul-americana), Cerrado (berço das águas do Brasil — relevante para Tocantins), resíduos plásticos nos oceanos, agrotóxicos e saúde pública. Repertório: Boaventura de Sousa Santos e "epistemologias do Sul"; Hans Jonas e o "princípio responsabilidade"; Enrique Leff e a ecologia política. No Tocantins: queimadas no Cerrado, garimpo ilegal no Araguaia, Ilha do Bananal e seus impactos. Proposta: legislação ambiental mais rigorosa, educação ambiental, transição energética, demarcação de terras indígenas.', ['Como a questão do Cerrado (bioma do Tocantins) pode ser usada como repertório em uma redação sobre meio ambiente?', 'Escreva uma redação sobre: "Desafios da preservação ambiental diante do desenvolvimento econômico no Brasil".']),
  createLesson('g3-red-b1-l13', 'L13: Simulado ENEM 2022 — Análise e Correção', 'redacao', 'Vamos estudar o tema e as redações nota 1000 do ENEM 2022: "Desafios para a valorização de comunidades e povos tradicionais no Brasil". Análise: por que esse tema foi escolhido (contexto político, ambiental, indígena); como as melhores redações construíram a tese; quais repertórios foram usados (Constituição de 1988, Convenção 169 da OIT, massacre de Haximu, Marco Temporal); como as propostas de intervenção foram elaboradas. Lição principal: repertório jurídico e histórico específico impressiona mais que filosofia genérica quando o tema é específico. Aplicaremos as lições: cada aluno reescreverá a introdução ou a proposta.', ['Qual foi o tema do ENEM 2022 para redação e por que ele é considerado de média dificuldade?', 'Analise: por que uma redação com repertório específico (Constituição, tratados) tem vantagem sobre uma com repertório genérico (Aristóteles sobre justiça) nesse tipo de tema?']),
  createLesson('g3-red-b1-l14', 'L14: Simulado ENEM 2023 — Análise e Correção', 'redacao', 'Tema do ENEM 2023: "Invisibilidade e registro civil: garantia de acesso à cidadania no Brasil". Contexto: ~3 milhões de brasileiros sem registro civil; populações mais afetadas: indígenas, quilombolas, ribeirinhos, sem-teto. Análise das redações nota 1000: como conectaram cidadania (Rousseau, Arendt), documentação como dignidade, invisibilidade social (Bauman, Zygmunt). Redações fracas: não souberam definir "invisibilidade" no sentido sociológico, ficaram no senso comum. Lições: dominar o conceito central do tema é a chave. Se o tema traz uma palavra com sentido específico (invisibilidade, protagonismo, resistência), defina-a no início.', ['Como o conceito de "invisibilidade social" foi usado pelas melhores redações do ENEM 2023?', 'Escreva uma introdução para o tema ENEM 2023 usando o conceito de cidadania de Hannah Arendt.']),
  createLesson('g3-red-b1-l15', 'L15: Tema — Desigualdade Social e Raça no Brasil', 'redacao', 'Desigualdade é o tema mais abrangente do ENEM, podendo aparecer com recortes de raça, gênero, renda, regional ou digital. Dados essenciais: coeficiente de Gini do Brasil ~0,53 (um dos maiores do mundo); negros ganham 56% do salário de brancos (IBGE 2023); 84% dos presos são negros ou pardos. Repertório: Abdias do Nascimento e o genocídio do povo negro; Sueli Carneiro e epistemicídio; Djamila Ribeiro e o "lugar de fala"; Clóvis Moura e o quilombismo. Literatura: Carolina de Jesus, Conceição Evaristo, Lima Barreto. Proposta: políticas afirmativas, reforma tributária progressiva, descolonização curricular. Cuidado: não cair no senso comum ("o Brasil é um país desigual, logo precisamos de igualdade").', ['Como os dados do IBGE sobre desigualdade racial podem ser usados como argumento em uma redação sem virar "só estatística"?', 'Escreva um parágrafo de desenvolvimento sobre desigualdade racial usando repertório de Abdias do Nascimento ou Sueli Carneiro.']),
  createLesson('g3-red-b1-l16', 'L16: Tema — Saúde Mental e Bem-Estar', 'redacao', 'Saúde mental ganhou destaque pós-pandemia e está na pauta do ENEM. Dados: depressão afeta 11,5 milhões de brasileiros (OMS); suicídio é a 4ª causa de morte entre 15-29 anos no Brasil; burnout foi reconhecido pela OMS como doença ocupacional em 2022. Ângulos: saúde mental na escola, impacto das redes sociais, saúde mental e trabalho precário, desigualdade no acesso a serviços de saúde mental (SUS). Repertório: Byung-Chul Han e "a sociedade do cansaço"; Freud e o sofrimento psíquico; Foucault e a história da loucura. Proposta: CAPS (Centros de Atenção Psicossocial), formação de professores, regulação de redes sociais para menores, redução da jornada de trabalho.', ['Por que "saúde mental" e "bem-estar" são temas que tendem a aparecer no ENEM? Qual o contexto social que os torna relevantes?', 'Escreva uma redação completa sobre: "O impacto das redes sociais na saúde mental dos adolescentes brasileiros".']),
  createLesson('g3-red-b1-l17', 'L17: Redação Completa — Treino com Tempo', 'redacao', 'Simulação de prova real: 1h30min para escrever uma redação completa. Tema inédito (similar ao ENEM). O processo: 10 min de planejamento (mapa mental, tese, argumentos, proposta), 60 min de escrita, 20 min de revisão (norma culta, coesão, proposta). Dicas de gestão de tempo: não risque excessivamente (limite de 7 rasuras por padrão ENEM), escreva a limpo o máximo possível, não deixe a proposta de intervenção para os últimos 5 min. Após o treino, trocar com colega para leitura crítica mútua. Autocorrigir usando o barema das 5 competências.', ['Qual é a distribuição de tempo ideal durante a prova de redação do ENEM (planejamento, escrita, revisão)?', 'Após escrever sua redação, corrija-a usando os critérios das 5 competências. O que você melhoraria?']),
  createLesson('g3-red-b1-l18', 'L18: Revisão do 1º Bimestre e Planejamento Individual', 'redacao', 'Revisão do 1º bimestre: consolidação das 5 competências, análise do progresso individual, identificação de pontos fracos persistentes. Cada aluno recebe uma análise personalizada: em qual competência precisa mais trabalho? Qual estratégia adotar? Plano de ação individual para o 2º bimestre. Importante: a nota na redação do ENEM real não é "sorte de tema" — é resultado de prática sistemática. Quem escreve 1 redação por semana de março a novembro melhora em média 150-200 pontos. Mostre dados de melhora real de alunos e construa compromisso com a prática.', ['Faça uma autoavaliação honesta: em qual das 5 competências você está mais fraco? Qual é seu plano de melhora?', 'Quantas redações completas você já escreveu neste bimestre? Estabeleça uma meta para o próximo bimestre.']),
];

export const redLessonsB2: Lesson[] = [
  createLesson('g3-red-b2-l1', 'L1: Tema — Educação e Escola do Século XXI', 'redacao', 'Educação é tema clássico e pode aparecer com recortes variados: educação integral, escola e tecnologia, evasão escolar, educação quilombola/indígena, privatização do ensino, currículo colonizado. Dados: 20% dos jovens de 15-17 anos não frequentam escola (PNAD 2023); Brasil está na 88ª posição no PISA 2022; taxa de analfabetismo: 5,6% (adultos). Repertório: Paulo Freire e a "educação bancária" vs. educação libertadora; Gramsci e o intelectual orgânico; Saviani e a pedagogia histórico-crítica; John Dewey e a educação pragmática. Temas quentes: educação a distância, homeschooling, BNCC, militarização de escolas, fechamento de escolas rurais.', ['Como o conceito de "educação bancária" de Paulo Freire pode ser usado para criticar modelos pedagógicos autoritários?', 'Escreva uma redação sobre: "A evasão escolar no Ensino Médio e seus impactos sociais".']),
  createLesson('g3-red-b2-l2', 'L2: Tema — Trabalho, Automação e Futuro do Emprego', 'redacao', 'A automação tecnológica está transformando o mercado de trabalho. Dados: 54% dos empregos brasileiros têm alto risco de automação nos próximos 20 anos (IPEA); plataformas digitais (Uber, iFood) criaram trabalho precário sem direitos trabalhistas. Repertório: Karl Marx e a mais-valia; Ricardo Antunes e a "classe-que-vive-do-trabalho"; Byung-Chul Han e a "sociedade do desempenho"; Zygmunt Bauman e o trabalho líquido. Ângulos: uberização do trabalho, reforma trabalhista, desemprego estrutural, necessidade de nova formação profissional, renda básica universal (debate de Andrew Yang vs. economistas clássicos). Tocantins: agronegócio e mecanização, turismo como alternativa de emprego.', ['Como o conceito de "uberização" difere do emprego formal e quais direitos trabalhistas estão em risco nesse modelo?', 'Escreva um parágrafo de desenvolvimento sobre automação e desemprego usando repertório de Marx ou Ricardo Antunes.']),
  createLesson('g3-red-b2-l3', 'L3: Tema — Gênero, Feminismo e Igualdade', 'redacao', 'Gênero e feminismo têm aparecido com frequência crescente no ENEM. Dados: feminicídio é a 5ª maior causa de morte de mulheres no Brasil; mulheres ganham 22% menos que homens em cargos iguais (IBGE); 52% dos universitários são mulheres, mas só 38% dos cargos de liderança são femininos. Repertório: Simone de Beauvoir ("não se nasce mulher, torna-se mulher"); Judith Butler e a performatividade de gênero; bell hooks e o feminismo interseccional; Djamila Ribeiro e o lugar de fala. Literatura: Clarice Lispector, Conceição Evaristo, Chimamanda Ngozi Adichie. Proposta: Lei Maria da Penha fortalecida, licença-parental igual, cotas para mulheres em cargos executivos, educação não sexista.', ['Como o conceito de "interseccionalidade" amplia a análise das desigualdades de gênero?', 'Escreva uma redação sobre: "Desafios para a igualdade de gênero no mercado de trabalho brasileiro".']),
  createLesson('g3-red-b2-l4', 'L4: Tema — Povos Indígenas e Territórios', 'redacao', 'Povos indígenas: tema de alta recorrência pós-2019. Contexto: 305 etnias, 274 línguas; 13% do território nacional são terras indígenas demarcadas (Constituição 1988); Marco Temporal (2023) foi derrubado pelo STF mas ainda gera tensão. No Tocantins: Krahô, Karajá, Xerente, Javaé — culturas ricas ameaçadas pelo agronegócio e garimpo no Araguaia. Repertório: Ailton Krenak ("Ideias para adiar o fim do mundo"); Darcy Ribeiro e a formação do povo brasileiro; Viveiros de Castro e o perspectivismo ameríndio. Dados: 1/3 dos indígenas vivem em extrema pobreza; índices de suicídio 3x maior que média nacional. Proposta: demarcação de terras, consulta livre e prévia às comunidades (Convenção 169 da OIT), valorização das línguas indígenas na escola.', ['Qual a importância do pensamento de Ailton Krenak para repensar a relação entre humanidade e natureza?', 'Escreva uma redação sobre: "A luta dos povos indígenas pelo direito ao território no Brasil contemporâneo".']),
  createLesson('g3-red-b2-l5', 'L5: Estratégias para Temas Difíceis ou Surpresa', 'redacao', 'No dia do ENEM, você pode encontrar um tema que não estudou especificamente. Estratégia de emergência: (1) Leia os textos motivadores com atenção — eles sempre contêm pistas de argumento; (2) Identifique a área temática (social, ambiental, tecnológica, cultural); (3) Acione repertório transversal: Paulo Freire serve para educação E para qualquer processo de conscientização; Hannah Arendt serve para política E para cidadania E para violência; (4) Construa uma tese que você consegue defender — não tente ser muito original; (5) Use dados que você conhece de temas próximos. Exercício: temas "surpresa" propostos em aula — resolução em 10 minutos cada.', ['Como reagir quando o tema do ENEM é completamente inesperado? Descreva uma estratégia passo a passo.', 'Pratique: escreva uma introdução para o tema surpresa apresentado pelo professor em sala.']),
  createLesson('g3-red-b2-l6', 'L6: Tema — Alimentação, Agrotóxicos e Saúde', 'redacao', 'Alimentação saudável é direito humano e tema emergente. Dados: Brasil é o maior consumidor de agrotóxicos do mundo; 67% dos brasileiros estão acima do peso (IBGE); insegurança alimentar afeta 125 milhões de brasileiros (Rede PENSSAN). Repertório: Josué de Castro ("Geografia da Fome"); Vandana Shiva e a soberania alimentar; Naomi Oreskes e a negação científica por lobbies. Ângulos: agroecologia vs. agronegócio, fast food e obesidade infantil, desperdício de alimentos, subsídios ao agronegócio, alimentação escolar (PNAE) e agricultura familiar. Tocantins: produção de arroz e soja, pesca artesanal no Araguaia, alimentos indígenas tradicionais (piqui, pequi, buriti).', ['Por que o Brasil, grande produtor de alimentos, tem milhões de pessoas em insegurança alimentar? Qual a contradição aqui?', 'Escreva um parágrafo argumentativo sobre o uso de agrotóxicos e a saúde da população usando dados precisos.']),
  createLesson('g3-red-b2-l7', 'L7: Tema — Moradia, Urbanização e Direito à Cidade', 'redacao', 'Direito à moradia é garantido pela Constituição (art. 6º) mas 8 milhões de brasileiros vivem em favelas (IBGE). Déficit habitacional: 7,8 milhões de moradias. Urbanização acelerada sem planejamento gerou periferias sem infraestrutura, violência, enchentes recorrentes. Repertório: Henri Lefebvre e o "direito à cidade"; Ermínia Maricato e a segregação urbana brasileira; Milton Santos e o espaço urbano desigual. Ângulos: programa Minha Casa Minha Vida, regularização fundiária, mobilidade urbana, gentrificação, saneamento básico (52 milhões sem esgoto tratado). Proposta: reforma urbana, participação popular no planejamento, investimento em habitação popular, saneamento universal.', ['O que Henri Lefebvre entendia por "direito à cidade" e como esse conceito se aplica à realidade das periferias brasileiras?', 'Escreva uma redação sobre: "A falta de saneamento básico e seus impactos na saúde e dignidade da população periférica".']),
  createLesson('g3-red-b2-l8', 'L8: Revisão de Coesão — Articulação entre Parágrafos', 'redacao', 'Um erro grave no ENEM é ter parágrafos bons, mas desconexos. A articulação entre parágrafos é tão importante quanto a qualidade interna de cada um. Técnicas: (1) Última frase do parágrafo anterior prepara o tema do próximo; (2) Primeira frase do novo parágrafo retoma (sem repetir) a ideia anterior; (3) Conectivos interparágrafos: "Somando-se a isso...", "Em outra perspectiva...", "Considerando esse contexto..."; (4) Repetição controlada de palavra-chave temática que une o texto. Exercício prático: pegar uma redação do aluno e trabalhar exclusivamente a articulação entre parágrafos, sem mudar o conteúdo interno.', ['Qual a diferença entre coesão interna de um parágrafo e articulação entre parágrafos? Por que ambas importam?', 'Reescreva as transições entre os parágrafos desta redação (fornecida pelo professor) para melhorar a fluidez do texto.']),
  createLesson('g3-red-b2-l9', 'L9: Análise de Redações Nota 1000 — Desconstrução', 'redacao', 'Estudar redações nota 1000 é uma das formas mais eficazes de aprender. Método de análise: (1) Identifique a estratégia de contextualização usada; (2) Localize a tese e avalie se é específica ou genérica; (3) Analise o repertório usado em cada parágrafo; (4) Verifique a coesão (conectivos, retomadas, substituições); (5) Avalie os 5 elementos da proposta de intervenção; (6) Identifique pontos de norma culta avançada. Sessão de análise coletiva: 3 redações nota 1000 de diferentes anos do ENEM, comparando estratégias e aprendendo modelos. Crie seu "modelo mental" de redação ideal.', ['Após analisar redações nota 1000, qual estratégia de contextualização você considera mais eficaz? Por quê?', 'Escolha uma redação nota 1000 e identifique os 5 elementos da proposta de intervenção nela.']),
  createLesson('g3-red-b2-l10', 'L10: Tema — Racismo Estrutural e Sociedade', 'redacao', 'Racismo estrutural é conceito-chave para o ENEM contemporâneo. Definição (Silvio Almeida): racismo não é só ato individual, mas mecanismo sistêmico que perpassa instituições, leis, cultura e linguagem. Dados: negros são 74% dos assassinados no Brasil (Atlas da Violência); 70% dos mais pobres são negros; negros têm expectativa de vida 3 anos menor que brancos. Legislação: Lei Antirracismo (7.716/89), Estatuto da Igualdade Racial, cotas nas universidades (Lei 12.711/2012). Repertório: Frantz Fanon ("Pele negra, máscaras brancas"); Stuart Hall e identidade cultural; Abdias do Nascimento. No Tocantins: povos Krahô e Karajá e racismo contra indígenas.', ['Qual a diferença entre "racismo individual" e "racismo estrutural"? Por que a distinção é importante para a argumentação?', 'Escreva uma redação sobre: "Os impactos do racismo estrutural no acesso de negros à educação e ao mercado de trabalho".']),
  createLesson('g3-red-b2-l11', 'L11: Tema — Democracia, Política e Cidadania', 'redacao', 'Democracia é tema sensível mas essencial. Ângulo seguro: focar em participação, transparência e direitos, não em partidos. Dados: abstenção eleitoral crescente entre jovens; desinformação afeta qualidade do voto; 37% dos brasileiros apoiaram golpe em pesquisa de 2022 (Ipsos). Repertório: Hannah Arendt e a condição humana (ação política); Rousseau e o contrato social; Alexis de Tocqueville e a tirania da maioria; Norberto Bobbio e o mínimo democrático. Ângulos: fake news e democracia, participação popular além do voto, accountability, corrupção e confiança institucional. Proposta: educação política nas escolas, fortalecimento de conselhos comunitários, transparência nos gastos públicos, regulação de plataformas digitais.', ['Por que Hannah Arendt distingue "poder legítimo" de "violência" e como isso se aplica à crise democrática contemporânea?', 'Escreva uma redação sobre: "A desinformação como ameaça à democracia brasileira".']),
  createLesson('g3-red-b2-l12', 'L12: Simulado Completo — ENEM Estilo', 'redacao', 'Simulado de redação em condições de prova: coletânea de textos + tema inédito + 1h30min. Tema do simulado: definido pelo professor na aula (temática contemporânea, alta probabilidade de cair). Protocolo: ler coletânea (5 min), planejar (10 min), escrever (65 min), revisar (10 min). Após entrega, correção coletiva: professor corrige uma redação em tempo real no quadro, apontando pontos de C1 a C5. Alunos identificam os mesmos pontos em suas próprias redações. Meta: identificar padrão de erro e criar estratégia pessoal de melhoria.', ['Qual é o maior erro que você cometeu neste simulado? Como pretende evitá-lo na prova real?', 'Comparando com simulados anteriores, você nota progresso em alguma competência específica? Em qual você ainda precisa melhorar mais?']),
  createLesson('g3-red-b2-l13', 'L13: Tema — Ciência, Negacionismo e Verdade', 'redacao', 'Negacionismo científico é fenômeno político-epistemológico relevante. Casos: negacionismo climático, antivacina, terraplanismo, negacionismo do Holocaust. No Brasil: 2020-2022 foram anos de forte negacionismo institucional (covid, vacinas, ciência). Repertório: Francis Bacon e o método indutivo; Karl Popper e a falsificabilidade; Naomi Oreskes ("Merchants of Doubt"); Isabelle Stengers e a "cosmopolítica". O que é ciência: hipótese → experimento → revisão por pares → consenso científico (IPCC, OMS). Por que o negacionismo avança: algoritmos de recomendação, viés de confirmação, politização da ciência, desconfiança institucional. Proposta: letramento científico nas escolas, regulação de plataformas, financiamento público à ciência.', ['O que caracteriza uma afirmação científica vs. uma opinião? Como o método científico protege contra o negacionismo?', 'Escreva uma redação sobre: "O negacionismo científico e suas consequências para a saúde pública brasileira".']),
  createLesson('g3-red-b2-l14', 'L14: Tema — Envelhecimento e Direitos dos Idosos', 'redacao', 'Brasil envelhece rápido: em 2050, 1/4 da população terá mais de 60 anos. Estatuto do Idoso (Lei 10.741/2003) e Política Nacional da Pessoa Idosa garantem direitos, mas a efetividade é baixa. Dados: violência contra idosos cresceu 60% na última década; 30% dos idosos vivem com filhos por necessidade econômica; pensão insuficiente para 40% dos aposentados rurais. Ângulos: abandono de idosos, saúde mental na terceira idade, CAPS Idoso, previdência social, discriminação etária (ageismo), contribuição econômica e cultural dos idosos. Proposta: ampliação dos CAPS e ILPI públicas, programa de combate ao ageismo, ampliação da cobertura previdenciária rural.', ['O que é ageismo e como ele se manifesta no mercado de trabalho e na sociedade brasileira?', 'Escreva uma redação sobre: "Desafios do envelhecimento da população brasileira e a valorização dos idosos".']),
  createLesson('g3-red-b2-l15', 'L15: Tema — Lgbtqiapn+ e Direitos Civis', 'redacao', 'Direitos da população LGBTQIAPN+ é tema que exige cuidado e repertório sólido. Dados: Brasil tem uma das maiores taxas de assassinato de pessoas trans do mundo; homofobia cresceu 20% entre 2019-2022. Legislação: STF criminalizou a homofobia equiparada ao racismo (2019); casamento civil igualitário reconhecido desde 2011 pelo CNJ. Ângulos: educação e combate à homofobia, saúde integral LGBTQIAPN+, violência e subnotificação, identidade de gênero e documentos, adoção por casais homoafetivos. Repertório: Judith Butler e performatividade de gênero; Michel Foucault ("História da Sexualidade"); Monique Wittig. Proposta: implementação de políticas de combate à discriminação, inclusão de educação para diversidade nas escolas, ampliação de políticas de saúde específicas.', ['Como o conceito de "performatividade de gênero" de Judith Butler questiona a ideia de identidade de gênero como algo natural ou fixo?', 'Escreva uma redação sobre: "Violência e discriminação contra a população LGBTQIAPN+ no Brasil: caminhos para a garantia de direitos".']),
  createLesson('g3-red-b2-l16', 'L16: Autocorreção e Feedback Cruzado', 'redacao', 'Aprender a corrigir sua própria redação é habilidade essencial. Protocolo de autocorreção: (1) Leia em voz alta — você ouve erros que não vê; (2) Verifique a coerência: cada parágrafo sustenta a tese?; (3) Cheque a coesão: os conectivos fazem sentido?; (4) Revise a norma culta com seu "checklist pessoal"; (5) Avalie a proposta de intervenção com os 5 elementos. Feedback cruzado: troque sua redação com um colega e dê uma nota por competência com justificativa. Discuta as diferenças de avaliação. O professor árbitro resolve divergências. Essa prática desenvolve senso crítico e autoconsciência textual.', ['Quais são os passos do protocolo de autocorreção de redação? Por que ler em voz alta ajuda?', 'Após trocar redações com um colega, quais diferenças entre sua autoavaliação e a avaliação do colega você identificou?']),
  createLesson('g3-red-b2-l17', 'L17: Redação Completa com Devolutiva Individual', 'redacao', 'Redação completa em sala com correção e devolutiva individual do professor. Tema: recente e de alta probabilidade para o ENEM 2026. Protocolo de correção: professor usa barema oficial das 5 competências. Devolutiva individual: cada aluno recebe sua redação corrigida com notas por competência, marcação dos erros mais frequentes e orientação personalizada. Meta: cada aluno identifica seus 3 erros mais frequentes e cria estratégia de eliminação. Tabela de progresso: comparar notas de simulados anteriores. Visualizar evolução motiva a continuar.', ['Olhando para a devolutiva do professor, quais foram seus 3 principais pontos de melhoria nesta redação?', 'Crie um plano de ação pessoal com 3 estratégias específicas para melhorar suas competências mais fracas até o ENEM.']),
  createLesson('g3-red-b2-l18', 'L18: Revisão do 2º Bimestre — Sprint para o ENEM', 'redacao', 'Revisão geral do 2º bimestre e ajuste de rota. Contagem regressiva: quantas semanas até o ENEM 2026? Plano de treinamento: meta de 1 redação por semana até a prova. Rotina ideal: 2ª feira — escolher tema, 3ª feira — pesquisar repertório, 4ª feira — planejar redação, 5ª feira — escrever, 6ª feira — autocorrigir. Banco de repertório pessoal: cada aluno deve ter uma "agenda de redação" com pelo menos 15 filósofos/pensadores, 10 dados estatísticos, 5 referências literárias, 5 referências cinematográficas. Motivação: lembre que a redação pode ser a diferença entre medicina e outro curso. Vale o esforço.', ['Como você pretende organizar sua preparação para a redação do ENEM nos próximos meses? Qual é sua meta de nota?', 'Monte seu "banco de repertório pessoal": liste pelo menos 10 pensadores/filósofos com a ideia principal de cada um que você pode usar em redações.']),
];

export const redLessonsB3: Lesson[] = [
  createLesson('g3-red-b3-l1', 'L1: Sprint Final — Estratégia Global para o ENEM', 'redacao', 'Chegamos ao bimestre decisivo. O ENEM de novembro está próximo. Estratégia global: (1) Consolide o que já domina — não tente aprender coisas novas radicalmente diferentes; (2) Identifique seus 2-3 maiores pontos fracos e foque neles; (3) Aumente frequência de simulados (pelo menos 2/semana); (4) Revise seu banco de repertório semanalmente; (5) Pratique gestão de tempo. Neste bimestre: focaremos em prática intensiva, análise de erros recorrentes e simulados com correção rápida. Cada redação escrita agora vale ouro — são os últimos treinos antes do jogo decisivo.', ['Quais são suas 3 maiores forças e suas 3 maiores fraquezas na redação ENEM neste momento?', 'Monte um cronograma detalhado de estudos de redação para as próximas 8 semanas antes do ENEM.']),
  createLesson('g3-red-b3-l2', 'L2: Tema — Segurança Pública e Sistema Prisional', 'redacao', 'Segurança pública sob ângulo estrutural: o Brasil tem a 3ª maior população carcerária do mundo (900 mil presos); sistema prisional é "escola do crime" (reincidência ~70%); encarceramento em massa afeta desproporcionalmente jovens negros periféricos. Modelo alternativo: justiça restaurativa, medidas alternativas à prisão, reintegração social. Repertório: Michel Foucault ("Vigiar e Punir"); Alessandro Baratta e criminologia crítica; Loïc Wacquant e o "estado penal" como resposta à questão social. Dados: custo mensal por preso no Brasil (~R$2.500) vs. por aluno (~R$700). Proposta: investimento em prevenção, políticas de reintegração, reforma do sistema prisional, justiça restaurativa para crimes sem violência.', ['Como Foucault analisa a prisão como instituição disciplinar e por que ela fracassa em reduzir o crime?', 'Escreva uma redação sobre: "A falência do sistema prisional brasileiro e os desafios da segurança pública".']),
  createLesson('g3-red-b3-l3', 'L3: Tema — Infância, Adolescência e Proteção', 'redacao', 'Crianças e adolescentes têm proteção especial (ECA — Lei 8.069/1990, considerado um dos mais avançados do mundo). Realidade: 1,5 milhão de crianças em trabalho infantil; 30% dos jovens de 15-29 anos são "nem-nem" (nem estudam nem trabalham); violência sexual afeta 1 em 4 meninas brasileiras. Ângulos: trabalho infantil no campo (Tocantins: colheita de abacaxi), exploração sexual, drogas e vulnerabilidade juvenil, medida socioeducativa vs. redução da maioridade penal. Repertório: Philippe Ariès e a construção histórica da infância; Winnicott e o desenvolvimento infantil; Janusz Korczak e o direito das crianças. Proposta: CRAS e CREAS fortalecidos, Conselho Tutelar efetivo, programas de contraturno escolar, erradicação do trabalho infantil.', ['Por que a infância é considerada uma "construção histórica" e como isso afeta as políticas de proteção à criança?', 'Escreva uma redação sobre: "O trabalho infantil no Brasil: causas, consequências e caminhos de superação".']),
  createLesson('g3-red-b3-l4', 'L4: Simulado com Correção Imediata', 'redacao', 'Simulado de alta pressão: tema inédito, 1h30min, correção coletiva imediata após entrega. Método de correção rápida: professor seleciona 3-4 redações (com permissão dos alunos), projeta e corrige em vivo, indicando pontos específicos de C1 a C5. Classe avalia junto. Discussão: onde a maioria errou? Qual é o padrão de erro coletivo? Isso revela pontos que precisam de reforço coletivo. Feedback imediato acelera o aprendizado: o aluno ainda "lembra" do raciocínio que usou e pode entender melhor onde falhou.', ['O que você aprendeu observando a correção coletiva que não havia percebido na sua própria redação?', 'Após o simulado de hoje, quais ajustes você fará na sua estratégia de escrita para o próximo simulado?']),
  createLesson('g3-red-b3-l5', 'L5: Tema — Saúde Pública e Sistema SUS', 'redacao', 'O SUS (Sistema Único de Saúde) é um dos maiores sistemas públicos de saúde do mundo, mas enfrenta subfinanciamento crônico. Dados: Brasil gasta ~9% do PIB em saúde (OMS recomenda 10%); 75% dos brasileiros dependem exclusivamente do SUS; desigualdade regional: Norte e Nordeste têm piores indicadores. Ângulos: fila de espera, UPA superlotada, desigualdade regional de saúde, saúde mental, saúde indígena, financiamento privado vs. público. Repertório: Sérgio Arouca e a Reforma Sanitária; Jairnilson Paim e o SUS; Declaração de Alma-Ata (1978): saúde como direito. Proposta: aumento do financiamento público, ampliação do Programa Mais Médicos, telemedicina para regiões remotas (como interior do Tocantins), fortalecimento da atenção primária.', ['Por que o SUS é considerado uma conquista histórica mesmo com todos os seus problemas? Qual a sua importância para a população pobre?', 'Escreva uma redação sobre: "Os desafios do sistema público de saúde para garantir atendimento universal e igualitário".']),
  createLesson('g3-red-b3-l6', 'L6: Tema — Amazônia, Biodiversidade e Soberania Nacional', 'redacao', 'A Amazônia ocupa 60% do território brasileiro e concentra 10% da biodiversidade mundial. Desmatamento atingiu 11.568 km² em 2022 (PRODES/INPE). Ângulos: garimpo ilegal, madeireiros, pressão agrícola (soja e gado), soberania nacional vs. pressão internacional, biopirataria, povos da floresta. Repertório: Euclides da Cunha e a Amazônia; Chico Mendes como mártir ambientalista; Ailton Krenak; Declaração dos Direitos da Natureza (Constituição do Equador). Tocantins: Ilha do Bananal (maior ilha fluvial do mundo), parques estaduais, garimpo no Araguaia. Proposta: fortalecimento do IBAMA e ICMBio, bioeconomia (uso sustentável da floresta), demarcação de terras indígenas, pagamento por serviços ambientais.', ['Por que o desmatamento da Amazônia é uma questão tanto ambiental quanto de soberania nacional?', 'Escreva uma redação sobre: "O desmatamento da Amazônia e o papel do Brasil na crise climática global".']),
  createLesson('g3-red-b3-l7', 'L7: Norma Culta Final — Revisão dos Pontos Críticos', 'redacao', 'Revisão intensiva de norma culta para o ENEM. Os 10 erros mais frequentes que derrubam a C1: (1) Concordância verbal com sujeito composto; (2) Concordância com pronomes indefinidos (nenhum, cada um); (3) Regência de verbos como "visar", "aspirar", "preferir", "obedecer"; (4) Crase antes de verbos, pronomes femininos e masculinos; (5) Vírgula entre sujeito e verbo; (6) Uso indevido de gerúndio (gerundismo); (7) Confusão entre "há" e "a"; (8) Uso incorreto de "onde" com verbos de estado; (9) Pronome relativo "cujo" sem artigo depois; (10) Fragmento de oração (oração sem verbo principal). Exercício: identificar e corrigir esses erros em textos propositalmente errados.', ['Dos 10 erros listados, quais você comete com mais frequência? Como vai monitorar e eliminar esses erros na prova?', 'Corrija os 10 erros de norma culta no texto fornecido pelo professor, identificando qual tipo de erro cada um representa.']),
  createLesson('g3-red-b3-l8', 'L8: Tema — Migração, Refugiados e Xenofobia', 'redacao', 'Migrações e refugiados é tema de altíssima relevância contemporânea. Dados: 117 milhões de deslocados no mundo (ACNUR 2024); Brasil tem 500 mil refugiados reconhecidos (venezuelanos são maioria); xenofobia contra nordestinos é forma interna de discriminação. Ângulos: guerra e deslocamento, refugiados climáticos (novo conceito), xenofobia e integração, Lei de Migração (13.445/2017), Estatuto do Refugiado. Repertório: Hannah Arendt e o apátrida ("Origins of Totalitarianism"); Simmel e o "estrangeiro"; Zygmunt Bauman e os "refugos humanos". No Tocantins: migração interna de nordestinos, quilombolas deslocados por barragens. Proposta: política nacional de integração de refugiados, combate à xenofobia, regularização de imigrantes.', ['Como Hannah Arendt analisa a condição dos apátridas e refugiados como um problema de direitos humanos?', 'Escreva uma redação sobre: "Desafios da integração de refugiados e migrantes na sociedade brasileira".']),
  createLesson('g3-red-b3-l9', 'L9: Simulado Temático — Temas de Alta Probabilidade 2026', 'redacao', 'Com base na análise dos temas recorrentes do ENEM (2010-2024) e do cenário contemporâneo, os temas de maior probabilidade para 2026 são: (1) Saúde mental; (2) Inteligência artificial e trabalho; (3) Mudanças climáticas; (4) Desigualdade e pobreza; (5) Povos originários; (6) Desinformação e democracia. Simulado: escreva uma redação sobre um dos temas acima (sorteio). 1h30min. Após, discussão: quais temas geraram mais dificuldade? Por quê? Revisão de repertório específico para os temas mais difíceis para a classe. Priorizar os temas de maior dificuldade coletiva.', ['Por que prever os temas prováveis do ENEM e preparar repertório específico é uma estratégia válida?', 'Após o simulado, identifique: seu repertório era suficiente? O que faltou? Como você pode suprir essa lacuna?']),
  createLesson('g3-red-b3-l10', 'L10: Tema — Inteligência Artificial e Ética', 'redacao', 'IA está transformando o mundo e pode aparecer no ENEM. Dados: ChatGPT atingiu 100 milhões de usuários em 2 meses (2023); 85 milhões de empregos podem ser automatizados até 2025 (WEF); IA generativa levanta questões de direitos autorais, deepfakes, desinformação. Repertório: Nick Bostrom e o "superinteligência"; Norberto Bobbio e a ética nas novas tecnologias; Luciano Floridi e a "filosofia da informação"; Hans Jonas e o princípio responsabilidade. Ângulos: IA e desemprego, IA e discriminação (algoritmos racistas), IA na saúde, IA na educação, regulação de IA (EU AI Act como referência). Proposta: regulação ética de IA, educação para literacia digital, fundo de transição para trabalhadores deslocados.', ['Quais são os principais riscos éticos da inteligência artificial para a sociedade? Como o princípio de responsabilidade de Hans Jonas se aplica aqui?', 'Escreva uma redação sobre: "Inteligência artificial e o futuro do trabalho: desafios para a sociedade brasileira".']),
  createLesson('g3-red-b3-l11', 'L11: Tema — Esporte, Corpo e Sociedade', 'redacao', 'Esporte pode aparecer como tema em múltiplos ângulos: inclusão e exclusão pelo esporte, esporte como mobilidade social, corpo e padrões de beleza, doping, mega-eventos (Copa, Olimpíadas) e legado social. Dados: Brasil gastou R$37 bilhões na Copa 2014, com questionável legado social; esporte profissional é altamente elitizado; 70% dos alunos de escola pública não praticam esporte regularmente. Repertório: Bourdieu e o "habitus" corporal; Le Breton e o corpo na modernidade; Norbert Elias e o processo de civilização pelo esporte. Ângulos: esporte e saúde pública, superexposição de atletas nas redes sociais, paralimpíadas e inclusão, violência no futebol (racismo e homofobia). No Tocantins: esportes de aventura (Jalapão, Taquaruçu).', ['Como Bourdieu relaciona a prática esportiva a diferentes classes sociais? Isso ainda é verdade no Brasil contemporâneo?', 'Escreva uma redação sobre: "O esporte como instrumento de inclusão social ou como reflexo da desigualdade brasileira".']),
  createLesson('g3-red-b3-l12', 'L12: Simulado Completo — Condições de Prova Real', 'redacao', 'Simulado final do bimestre em condições idênticas às da prova real: celular guardado, mesa limpa, folha de rascunho, folha de redação, 1h30min, tema inédito apresentado na hora. Protocolo estrito: sem consulta, sem comunicação, sem qualquer apoio. Após entrega, pausa de 10 min e correção coletiva. Finalidade: dessensibilizar a ansiedade de prova, identificar como o desempenho varia sob pressão real vs. treino confortável, desenvolver confiança. Após correção, cada aluno estabelece metas específicas para o simulado final do 4º bimestre.', ['Seu desempenho sob condição de prova real foi diferente do que nos treinos? O que explica essa diferença?', 'Quais estratégias você usou para gerenciar a ansiedade durante o simulado? Funcionaram?']),
  createLesson('g3-red-b3-l13', 'L13: Repertório Literário Brasileiro para o ENEM', 'redacao', 'A literatura brasileira é um repertório valioso e pouco explorado pelos alunos. Autores e obras essenciais: Machado de Assis (Dom Casmurro — ciúme, narrador não confiável; Memórias Póstumas — crítica social, niilismo); Lima Barreto (preconceito racial, marginalização); Graciliano Ramos (Vidas Secas — seca, desumanização, migração); João Guimarães Rosa (Grande Sertão: Veredas — sertão, identidade, dualidade bem/mal); Carolina de Jesus (Quarto de Despejo — pobreza, raça, gênero, resistência); Conceição Evaristo (escrevivência, afrofuturismo); Clarice Lispector (subjetividade, feminino, existência). Usar literatura como repertório: citar obra, autor e ideia relevante para o argumento.', ['Por que "Quarto de Despejo" de Carolina de Jesus é uma obra especialmente relevante para temas de pobreza e desigualdade no ENEM?', 'Escolha 3 obras literárias brasileiras e escreva como usaria cada uma como repertório em uma redação sobre desigualdade social.']),
  createLesson('g3-red-b3-l14', 'L14: Repertório Filosófico e Sociológico Avançado', 'redacao', 'Ampliando o repertório filosófico e sociológico para nível avançado. Filosofia: (1) Habermas — ação comunicativa e esfera pública; (2) Rawls — justiça como equidade, véu da ignorância; (3) Amartya Sen — desenvolvimento como liberdade; (4) Martha Nussbaum — capacidades humanas; (5) Boaventura de Sousa Santos — epistemologias do Sul, colonialidade. Sociologia: (1) Zygmunt Bauman — modernidade líquida, identidade fluida; (2) Ulrich Beck — sociedade de risco; (3) Axel Honneth — reconhecimento e luta social; (4) Jessé Souza — "ralé brasileira", subcidadania. Como usar: não apenas citar o nome, mas conectar a ideia ao argumento da redação.', ['Como o conceito de "véu da ignorância" de Rawls poderia ser usado em uma redação sobre desigualdade social?', 'Escolha 2 dos filósofos/sociólogos listados e escreva parágrafos de desenvolvimento usando as ideias deles para argumentar sobre temas diferentes.']),
  createLesson('g3-red-b3-l15', 'L15: Tema — Cultura, Identidade e Diversidade', 'redacao', 'Cultura e identidade nacional é tema rico e multifacetado. O Brasil é uma das nações mais diversas do mundo: 305 etnias indígenas, 5.000 quilombos, 200 línguas vivas, influências africanas, europeias, asiáticas. Ângulos: folclore e identidade regional, patrimônio imaterial ameaçado, cultura de massa vs. cultura popular, imperialismo cultural (americanização), identidade brasileira entre contradições. Repertório: Stuart Hall e a diáspora cultural; Edward Said e o orientalismo; Homi Bhabha e a hibridização cultural; Gilberto Freyre e a mestiçagem (crítica e contexto); Sílvio Romero e o folclore. No Tocantins: Caprichosa de Palmas, Krahô e Karajá, festas do Divino, culinária do Cerrado.', ['Como Stuart Hall analisa a identidade cultural como algo fluido e em constante construção, não fixo?', 'Escreva uma redação sobre: "A diversidade cultural brasileira como patrimônio a ser preservado frente à globalização".']),
  createLesson('g3-red-b3-l16', 'L16: Gestão de Ansiedade e Preparação Mental para o ENEM', 'redacao', 'Preparação mental é tão importante quanto o conteúdo. A ansiedade de prova afeta o desempenho: pesquisas mostram que técnicas de respiração e visualização positiva melhoram a performance em até 15%. Antes do ENEM: (1) Durma 8h nas 3 noites anteriores — memória consolida durante o sono; (2) Não revise coisas novas na véspera; (3) Coma bem antes da prova; (4) Chegue 30min cedo; (5) Leve água e lanche; (6) Se travar, respire, pule a questão, volte. Durante a redação: planejamento nos primeiros 10 min é investimento, não perda de tempo. Se o tema for difícil para você, todos os outros também acharam. Estratégia antes da entrega: leia toda a redação uma última vez.', ['Quais estratégias você vai usar para gerenciar a ansiedade no dia do ENEM? Descreva sua rotina ideal na véspera e no dia da prova.', 'Faça uma simulação mental: visualize-se recebendo o caderno de prova, lendo o tema da redação e iniciando seu planejamento. O que você sente? O que pode melhorar?']),
  createLesson('g3-red-b3-l17', 'L17: Redação de Alta Performance — Revisão das Melhores Produções da Turma', 'redacao', 'Sessão especial: seleção das melhores redações da turma (com permissão dos autores) para análise coletiva. O que as redações nota alta têm em comum? Identificar padrões de sucesso: estratégias de contextualização que funcionaram, teses bem recortadas, repertórios originais, propostas de intervenção criativas. Cada aluno analisa 2 redações de colegas e escreve: (1) O que eu aprendi com essa redação; (2) Uma estratégia que vou incorporar na minha. Troca de modelos é mais eficaz que repetição de erros. Celebrar o progresso da turma.', ['Após analisar redações de colegas, qual técnica ou estratégia você mais quer incorporar na sua escrita? Por quê?', 'Escreva uma carta para você mesmo, do início do ano até agora: como você evoluiu na redação? O que ainda precisa melhorar?']),
  createLesson('g3-red-b3-l18', 'L18: Contagem Regressiva — Últimas Semanas antes do ENEM', 'redacao', 'Preparação final para o ENEM. Checklist das últimas semanas: ✓ Continuar escrevendo 1 redação por semana; ✓ Revisar banco de repertório; ✓ Fazer pelo menos 2 simulados completos (redação + objetivas); ✓ Reler suas redações melhores para ativar o "modo certo" de escrita; ✓ Dormir bem; ✓ Conversar com quem te apoia. Mensagem final: o ENEM não é o fim do mundo. É uma porta. Você já passou por 3 anos de preparação. Você tem recursos que não existiam antes. Confia no treino. No dia da prova, não seja um aluno — seja um escritor. Escreva com autoridade.', ['Quais são as 5 coisas mais importantes que você aprendeu sobre redação ao longo deste ano?', 'Escreva uma redação final completa sobre o tema apresentado pelo professor: demonstre tudo que aprendeu ao longo do ano.']),
];

export const redLessonsB4: Lesson[] = [
  createLesson('g3-red-b4-l1', 'L1: Pós-ENEM — Reflexão e Novos Horizontes', 'redacao', 'O ENEM passou. Momento de reflexão: Como foi? O que funcionou? O que não funcionou? A redação não termina com o ENEM — escrever bem é uma habilidade para a vida toda. Na faculdade, você vai escrever relatórios, TCC, artigos, e-mails profissionais, projetos. No trabalho, comunicação escrita eficaz diferencia profissionais. Nesta última etapa, vamos expandir o horizonte: a escrita além do ENEM. Discutiremos: redação acadêmica, escrita criativa, jornalismo, blogs e escrita digital. Objetivo: saírem daqui como comunicadores competentes, não apenas "aprovados no ENEM".', ['O que você aprendeu sobre escrever ao longo deste ano que vai carregar para a vida?', 'Reflita sobre sua jornada na redação: qual foi seu maior crescimento? Qual foi seu maior desafio?']),
  createLesson('g3-red-b4-l2', 'L2: Escrita Acadêmica — Do ENEM para a Faculdade', 'redacao', 'A escrita acadêmica tem características distintas da dissertação do ENEM. Semelhanças: tese clara, argumentação lógica, coesão. Diferenças: (1) Referenciação formal (ABNT, APA); (2) Impessoalidade (não usa "eu"); (3) Linguagem técnica específica da área; (4) Revisão por pares; (5) Estrutura IMRaD (Introdução, Método, Resultado, Discussão) para artigos científicos. Introdução à escrita acadêmica: abstract, referências, paráfrase vs. citação direta. Por que isso importa agora? Quem vai para a faculdade vai precisar desse conhecimento já no 1º semestre. Antecipar esse aprendizado é uma vantagem real.', ['Quais são as principais diferenças entre a redação do ENEM e a escrita acadêmica universitária?', 'Escreva um parágrafo acadênico sobre um tema de sua escolha usando linguagem impessoal e citação em formato ABNT.']),
  createLesson('g3-red-b4-l3', 'L3: Escrita Profissional — E-mail, Relatório, Currículo', 'redacao', 'Comunicação profissional escrita é habilidade valorizada no mercado de trabalho. E-mail profissional: assunto claro, saudação adequada, corpo objetivo, despedida formal. Erros comuns: gírias, abreviações de WhatsApp, responder "ok" para e-mail importante, tom passivo-agressivo. Relatório: estrutura (objetivo, desenvolvimento, conclusão), uso de dados e gráficos, linguagem clara e direta. Currículo: síntese de competências, experiências e objetivos — cada palavra conta. Carta de apresentação: personalizada, mostrando por que você é o candidato ideal. Exercício prático: escreva um e-mail profissional, um currículo básico e uma carta de apresentação para uma vaga imaginária.', ['Por que habilidades de comunicação escrita são tão valorizadas no mercado de trabalho contemporâneo?', 'Escreva um e-mail profissional solicitando uma entrevista de estágio em uma empresa de sua escolha.']),
  createLesson('g3-red-b4-l4', 'L4: Escrita Criativa — Contando Histórias', 'redacao', 'A escrita criativa desenvolve habilidades que complementam a argumentação: sensibilidade para a linguagem, precisão vocabular, ritmo textual. Elementos do conto: personagem, conflito, ponto de virada, resolução (ou não). Narrador: primeira pessoa (intimidade), terceira pessoa (distância controlada), narrador onisciente. Diálogo: como escrever falas naturais. Descrição: mostrar, não apenas contar. Exercício: escreva um microconto (máximo 300 palavras) sobre um tema social (desigualdade, amor, solidão, violência). Após, ler e comentar em grupo: o que funcionou? Qual cena foi mais vívida? A escrita criativa aguça o olhar sobre o mundo.', ['O que você aprendeu sobre linguagem escrevendo ficção que pode se aplicar à sua escrita argumentativa?', 'Escreva um microconto de até 300 palavras com um tema social. Tente mostrar (com imagens e ações) em vez de apenas dizer.']),
  createLesson('g3-red-b4-l5', 'L5: Escrita para Redes Sociais — Comunicação Digital', 'redacao', 'Redes sociais são o espaço de escrita mais frequente para os jovens. Mas escrever bem nas redes é uma habilidade distinta: linguagem concisa, headline que prende, storytelling em formato curto, apelo emocional sem manipulação, hashtag estratégica, call-to-action. A diferença entre uma postagem de impacto e uma ignorada está nos primeiros 2 segundos. Ética da comunicação digital: desinformação, câmara de eco, responsabilidade pelo que compartilhamos. Exercício: criar uma thread de Twitter/X sobre um tema social, com 5 tweets encadeados, usando dados e argumento real. Depois, discutir: qual é a responsabilidade do comunicador digital?', ['Como o estilo de escrita para redes sociais difere da escrita formal? Que habilidades são comuns a ambas?', 'Crie uma thread de 5 posts sobre um problema social brasileiro usando dados reais, argumentação lógica e linguagem acessível.']),
  createLesson('g3-red-b4-l6', 'L6: Jornalismo e Opinião — Coluna e Editorial', 'redacao', 'O jornalismo de opinião (coluna e editorial) é a forma profissional de dissertação argumentativa. Estrutura de uma coluna: gancho (fato atual), tese, 2-3 argumentos, conclusão com virada ou proposta. Diferença do ENEM: o jornalismo de opinião pode ser mais subjetivo, usar ironia, ser mais direto na crítica. Grandes colunistas: Luis Fernando Verissimo (humor e crítica), Eliane Brum (reportagem e opinião), Hélio Schwartsman (filosofia e atualidade). Leitura de colunas reais e análise: como esses escritores constroem seus argumentos? O que os torna eficazes? Exercício: escreva uma coluna de opinião de 300-400 palavras sobre uma questão atual de Palmas/Tocantins.', ['Qual é a diferença estrutural e de tom entre uma redação do ENEM e uma coluna de opinião jornalística?', 'Escreva uma coluna de opinião (300-400 palavras) sobre um problema atual da sua cidade ou estado.']),
  createLesson('g3-red-b4-l7', 'L7: Poesia e a Linguagem em sua Forma Máxima', 'redacao', 'A poesia é a forma de escrita que mais exige atenção à linguagem. Estudar poesia melhora qualquer tipo de escrita: ensina precisão vocabular, musicalidade, imagem. Poetas brasileiros essenciais: Carlos Drummond de Andrade (A rosa do povo — social e existencial), Ferreira Gullar (Poema Sujo — exílio e memória), Cora Coralina (Goiás como Tocantins colonial — pertencimento e identidade regional), Manoel de Barros (Mato Grosso, do Sul — linguagem como brinquedo). Poesia contemporânea: slam e poesia periférica (Emicida, Criolo). Exercício: leitura e declamação de poemas. Escreva um poema livre sobre algo que importa para você.', ['O que a precisão da linguagem poética ensina sobre a qualidade da escrita em prosa argumentativa?', 'Escreva um poema livre sobre um tema que você considera importante para o Brasil ou para Tocantins.']),
  createLesson('g3-red-b4-l8', 'L8: Leitura como Base — Construindo o Hábito', 'redacao', 'Toda boa escrita começa na leitura. Pesquisas mostram: quem lê 30 min/dia tem vocabulário 3x maior que quem não lê; leitores têm empatia superior (neurociência: ficção ativa sistemas neurais de processamento social). Como construir o hábito: (1) Comece por gêneros que você já gosta (quadrinhos, crônicas, blogs, podcasts com texto); (2) Reserve um horário fixo; (3) Tenha um livro sempre acessível no celular (apps: Skoob, Kindle gratuito); (4) Meta realista: 10 páginas por dia = 5-6 livros por ano. Autores para começar: Luiz Ruffato, Eliane Brum, Conceição Evaristo, Pedro Aleixo, Itamar Vieira Junior.', ['Por que a leitura regular é a base mais eficaz de desenvolvimento de escrita? O que a neurociência diz sobre isso?', 'Crie um plano de leitura para os próximos 6 meses: quais livros você vai ler? Por quê? Como vai manter o hábito?']),
  createLesson('g3-red-b4-l9', 'L9: Escrita e Identidade Pessoal', 'redacao', 'A escrita revela e constrói quem somos. A "carta de apresentação" para a vida adulta — seja para vestibular, para uma bolsa, para um emprego — é sempre uma forma de escrita de si. O essay americano (como o pedido em aplicações para universidades internacionais) é uma narrativa pessoal de 650 palavras. Características: voz autêntica, experiência específica, reflexão sobre o que você aprendeu. Exercício de autoescrita: escreva um parágrafo sobre uma experiência que mudou sua forma de ver o mundo. Depois: como essa experiência molda quem você é hoje? Como você usaria isso numa carta de apresentação?', ['O que você aprenderia sobre si mesmo ao tentar escrever honestamente sobre sua trajetória de vida?', 'Escreva um parágrafo sobre uma experiência marcante que formou quem você é. Seja específico, não genérico.']),
  createLesson('g3-red-b4-l10', 'L10: Escrita Coletiva e Colaborativa', 'redacao', 'A escrita colaborativa é cada vez mais comum no mundo profissional e acadêmico. Em grupos de 4: escrever coletivamente uma redação do ENEM em 45 min. Divisão de trabalho: (1) Uma pessoa planeja; (2) Outra escreve a introdução; (3) Outra escreve os dois parágrafos de desenvolvimento; (4) Outra escreve a conclusão. Desafio: o texto deve ter coesão como se fosse de um só autor. Discussão após: como foi o processo? Onde surgiram conflitos? Como foram resolvidos? Escrever em grupo ensina: comunicação, negociação de ideias, clareza de pensamento, respeito pelo raciocínio do outro.', ['Quais foram os principais desafios de escrever em grupo? O que essa experiência ensinou sobre comunicação?', 'Após a redação coletiva, reflita: sua contribuição foi positiva para o grupo? O que você faria diferente?']),
  createLesson('g3-red-b4-l11', 'L11: Revisão Final das 5 Competências — Síntese', 'redacao', 'Revisão completa e sintética das 5 competências do ENEM. C1 — Norma culta: você domina os 10 pontos críticos? Faça teste rápido de correção. C2 — Compreensão do tema: você sabe escrever uma tese específica, não vaga? Escreva 3 teses para 3 temas em 10 min. C3 — Argumentação: seus parágrafos têm 3 camadas (tópico + desenvolvimento + conclusão parcial)? Escreva 1 parágrafo completo. C4 — Coesão: você usa 3 tipos de coesão (referencial, sequencial, lexical)? Identifique em um texto. C5 — Proposta de intervenção: você completa os 5 elementos? Escreva 3 propostas para 3 temas. Diagnóstico final: onde ainda há lacuna?', ['Após a revisão das 5 competências, você ainda tem alguma em que se sente inseguro? O que vai fazer para suprir essa lacuna antes do ENEM?', 'Faça um teste final: escreva uma redação completa em 1h usando todas as técnicas aprendidas ao longo do ano.']),
  createLesson('g3-red-b4-l12', 'L12: Projeto de Escrita — Tema Livre', 'redacao', 'Projeto final de escrita criativa/argumentativa — cada aluno escolhe o gênero: (a) Redação dissertativa sobre tema de sua escolha; (b) Crônica sobre a vida em Palmas/Tocantins; (c) Coluna de opinião para jornal escolar; (d) Microconto de ficção social; (e) Poema sobre identidade ou pertencimento. O critério de avaliação não é o gênero escolhido, mas a qualidade: coerência, uso da língua, originalidade, profundidade. Após produção, leitura pública voluntária em círculo de escritas. Propósito: celebrar o percurso e mostrar que escrever é um ato de liberdade e identidade.', ['Qual gênero você escolheu e por quê? O que esse texto representa para você?', 'Escreva seu projeto de escrita final. Dê o melhor de si — este texto representa quem você se tornou como escritor neste ano.']),
  createLesson('g3-red-b4-l13', 'L13: Debate — Redação, IA e Autenticidade', 'redacao', 'A inteligência artificial (ChatGPT, etc.) pode escrever redações. Isso muda tudo? Debate estruturado: Time 1 — "A IA democratiza o acesso à escrita de qualidade e deve ser usada como ferramenta de apoio"; Time 2 — "A escrita é expressão da pessoa humana e usar IA para redações é desonestidade intelectual". Após debate, reflexão individual: qual é a fronteira ética? Como a IA muda o que significa "saber escrever"? Qual competência humana permanece insubstituível? Importante: o ENEM detecta plágio (algoritmos de similaridade) e a escrita autêntica ainda é insubstituível na sala de prova.', ['Qual é a fronteira ética entre usar IA como ferramenta de apoio e usar IA para substituir sua própria escrita?', 'Reflita: o que você aprendeu neste ano que uma IA não pode aprender da mesma forma? Por que a escrita humana ainda importa?']),
  createLesson('g3-red-b4-l14', 'L14: Escrita e Cidadania — Comunicar para Transformar', 'redacao', 'A escrita é uma ferramenta de poder e transformação social. Manifesto, petição, carta aberta, abaixo-assinado — são formas de escrita que mudaram o mundo. Exemplos históricos: Declaração dos Direitos do Homem (1789), Manifesto Comunista (1848), Carta da Terra (2000), Manifesto Regionalista (Gilberto Freyre, 1926). No Brasil contemporâneo: manifestos de movimentos sociais (MST, MTST, Movimento Negro Unificado). Projeto em grupo: identifique um problema na sua escola ou comunidade em Palmas/Tocantins e escreva uma carta aberta ao poder público pedindo ação. Escrever para transformar é o uso mais nobre da linguagem.', ['Como a escrita pode ser um instrumento de cidadania e transformação social? Dê exemplos históricos e contemporâneos.', 'Em grupo, identifique um problema real da sua escola ou comunidade e escreva uma carta aberta ao poder público exigindo mudança.']),
  createLesson('g3-red-b4-l15', 'L15: Avaliação Final e Portfólio de Redação', 'redacao', 'Construção do portfólio final de redação: cada aluno seleciona suas 3 melhores redações do ano, uma de cada tipo (formal/dissertativa, criativa, pessoal/identitária) e escreve uma reflexão sobre cada uma: (1) Por que escolheu essa; (2) O que ela representa de sua evolução; (3) O que faria diferente hoje. O portfólio é entregue com uma "carta de apresentação" ao professor. Avaliação: não apenas a qualidade das redações, mas a qualidade da reflexão sobre elas — metalinguagem e autoconsciência como escritor. Portfólio pode ser usado para vestibulares e bolsas que solicitam amostras de escrita.', ['Quais foram as 3 redações que você mais se orgulhou de ter escrito este ano? O que cada uma representa para você?', 'Escreva a introdução do seu portfólio de redação: quem você era como escritor no começo do ano e quem você é agora?']),
  createLesson('g3-red-b4-l16', 'L16: Leitura Compartilhada — Grandes Textos da Literatura', 'redacao', 'Sessão de leitura compartilhada: cada aluno traz um trecho (1 parágrafo) de um texto que o marcou no último ano — pode ser livro, crônica, notícia, lyric de música, poema, discurso. Leitura em voz alta para a turma. Discussão: por que esse texto importou? O que o torna eficaz? Como a linguagem funciona nele? Essa sessão celebra a diversidade de gostos literários da turma e mostra que não existe "texto certo" — existe texto que ressoa. Objetivo final: cada aluno deve sair sabendo que tem autoridade para ler e escrever sobre o que lhe importa.', ['Qual texto você trouxe para compartilhar e por que ele importa para você? O que o torna especial como escrita?', 'Após ouvir os textos dos colegas, qual você gostaria de ler na íntegra? Por quê?']),
  createLesson('g3-red-b4-l17', 'L17: Encerramento — Carta para o Futuro', 'redacao', 'Atividade final de encerramento do ano letivo: cada aluno escreve uma carta para si mesmo no futuro — para ser aberta em 2031 (5 anos). A carta deve incluir: (1) Quem você é hoje, em 2026; (2) Seus sonhos e medos atuais; (3) O que aprendeu sobre escrever e sobre o mundo; (4) Uma pergunta que só o futuro você pode responder; (5) Uma mensagem de encorajamento para o futuro. Cartas são guardadas pelo professor em envelope lacrado e devolvidas na formatura ou por correio digital. Esta atividade encerra o ciclo: escrita como autoconhecimento e projeção de futuro.', ['O que você diria ao seu "eu" de 5 anos atrás sobre o que aprendeu? E o que diz para o "eu" de 5 anos à frente?', 'Escreva sua carta para o futuro. Seja honesto, específico e corajoso — este é um texto só seu.']),
  createLesson('g3-red-b4-l18', 'L18: Última Aula — Celebração e Gratidão', 'redacao', 'A última aula de Redação da 3ª Série é um momento de celebração. Não há prova, não há pressão — há partilha. Atividade: Roda de gratidão e memória. Cada aluno completa: "Este ano de redação me ensinou que..." e "A redação que mais me orgulhei de escrever foi... porque...". Leitura coletiva de um texto inspirador sobre a linguagem como ferramenta de humanidade. Encerramento com uma promessa: continuar escrevendo. Não porque há vestibular, mas porque há vida — e a vida merece ser narrada, analisada, questionada, celebrada. Parabéns, escritores.', ['Complete: "Este ano, aprendi que escrever é..." Explique o que essa frase significa para você agora.', 'Escreva um parágrafo de agradecimento — para alguém que te ajudou a crescer como pessoa e como escritor ao longo do Ensino Médio.']),
];
